// Converts ../artifacts.js (window.ARTIFACTS = <JSON>;, generated by
// video/gen_artifacts.mjs from REAL pipeline runs) into src/artifacts.json so
// the Remotion composition can import it. artifacts.js stays the single
// committed source of truth; the JSON is generated and gitignored.
// The payload is JSON.stringify output, so it is parsed as data - never executed.
import { readFileSync, writeFileSync } from "node:fs";
import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";

const here = dirname(fileURLToPath(import.meta.url));
const source = readFileSync(join(here, "..", "..", "artifacts.js"), "utf8");
const match = source.match(/^window\.ARTIFACTS\s*=\s*([\s\S]+);\s*$/);
if (!match) throw new Error("artifacts.js does not look like 'window.ARTIFACTS = <JSON>;'");
const artifacts = JSON.parse(match[1]);
const out = join(here, "..", "src", "artifacts.json");
writeFileSync(out, JSON.stringify(artifacts, null, 2) + "\n");
console.log("wrote", out);
